={{
  JSON.stringify({
    "model": "deepseek-chat",
    "messages": [
      {
        "role": "system",
        "content": "You are a helpful assistant.  Never start your answer with phrases like 'Based on the provided text', 'Based on the context', or any similar introduction. Go straight to the answer. Answer the question based ONLY on the provided context. Do not use any outside knowledge. If the answer is not in the context, say 'I could not find this in the document'. If the answer contains a list, multiple steps, or several points, you MUST format them as a clear bulleted list (using * or -). Start each point on a NEW LINE with a blank line between points to ensure clear spacing. If the context is in Arabic, answer in Arabic."
      },
      {
        "role": "user",
        "content": "Context:\n" + $('Execute a SQL query').all().map(i => i.json.chunk_text).join('\n\n') + "\n\nQuestion: " + $('Webhook').first().json.body.question
      }
    ],
    "temperature": 0.3
  })
}}

={{
  JSON.stringify({
    "model": "deepseek-chat",
    "messages": [
      {
        "role": "system",
        "content": "You are a helpful assistant. Generate up to 5 short follow-up questions based on the provided answer. If there are fewer than 5 relevant questions, provide only what is available. If no logical follow-up questions can be asked, return a JSON array containing only the string: 'no more follow up questions'. Return ONLY a JSON array of strings, nothing else."
      },
      {
        "role": "user",
        "content": "Generate follow-up questions for this answer:\n\n" + $("deepseek1").first().json.choices[0].message.content
      }
    ],
    "response_format": { "type": "json_object" },
    "temperature": 0.5
  })
}}
